import fs from "fs";
import { NextRequest, NextResponse } from "next/server";
import formidable from "formidable";

export const config = {
  api: { bodyParser: false },
};

export async function POST(req: NextRequest) {
  try {
    const form = formidable({
      keepExtensions: true,
      uploadDir: "./public/uploads",
    });

    const [fields, files] = await new Promise((resolve, reject) => {
      form.parse(req, (err, fields, files) => {
        if (err) reject(err);
        else resolve([fields, files]);
      });
    });

    if (!files.file) {
      return NextResponse.json({ error: "No file uploaded" }, { status: 400 });
    }

    console.log("Files received:", files); // Debugging file upload

    const filePath = files.file[0].filepath;
    const base64File = fs.readFileSync(filePath, { encoding: "base64" });

    // 🔹 OCR.space API call
    const ocrResponse = await fetch("https://api.ocr.space/parse/image", {
      method: "POST",
      headers: {
        apikey: "YOUR_OCR_SPACE_API_KEY",
        "Content-Type": "application/x-www-form-urlencoded",
      },
      body: new URLSearchParams({
        base64image: `data:application/pdf;base64,${base64File}`,
        isOverlayRequired: "true",
        language: "eng",
      }),
    });

    const result = await ocrResponse.json();
    console.log("OCR API Response:", JSON.stringify(result, null, 2)); // Debugging OCR API response

    if (!result || !result.ParsedResults) {
      return NextResponse.json({ error: "OCR API failed" }, { status: 500 });
    }

    const extractedText = result.ParsedResults[0]?.ParsedText || "";
    const isMarksheet = /subject|marks|percentage|grade|total/i.test(
      extractedText
    );

    return NextResponse.json(
      { text: extractedText, isMarksheet },
      { status: 200 }
    );
  } catch (error) {
    console.error("Error processing file:", error);
    return NextResponse.json(
      { error: "Error processing file" },
      { status: 500 }
    );
  }
}
